[DataContractAttribute]
public final class ConDemoNoteHeaderCreatedContract extends BusinessEventsContract
{
    Num noteId;
    Name subject;
}

Method.Source:
public static ConDemoNoteHeaderCreatedContract newFromNoteHeader(ConDemoNoteHeader _noteHeader)
{
    ConDemoNoteHeaderCreatedContract contract = new ConDemoNoteHeaderCreatedContract();
    contract.parmNoteId(_noteHeader.NoteId);
    contract.parmSubject(_noteHeader.Subject);
    return contract;
}

[DataMemberAttribute('NoteId')]
public Num parmNoteId(Num _noteId = noteId)
{
    noteId = _noteId;
    return noteId;
}

[DataMemberAttribute('Subject')]
public Name parmSubject(Name _subject = subject)
{
    subject = _subject;
    return subject;
}
